import { VectorStoreIndex, ContextChatEngine } from 'llamaindex';
import { verify } from '@vex/sdk';

// Initialize LlamaIndex
const index = await VectorStoreIndex.fromDocuments([
  // Load underwriting guidelines
]);
const queryEngine = index.asQueryEngine();

const safeUnderwrite = verify({
  guards: ['no_discrimination', 'index_freshness', 'relevant_context'],
  async fn(query: string) {
    const response = await queryEngine.query({
      query,
      chatHistory: [],
    });
    return `Underwriting decision: ${response.response}`;
  }
});

// Usage
const result = await safeUnderwrite('Risk assessment for 45yo applicant');
